export const EMBEDDED_MIGRATIONS: readonly Migration[] = [
  { name: "0001_init.sql", sql: "-- Slice 0 schema: persistence contract for Quay (per quay-spec.md §9).\n-- Foreign keys must be enabled at the connection level (PRAGMA foreign_keys = ON).\n\nCREATE TABLE repos (\n  repo_id TEXT PRIMARY KEY,\n  repo_url TEXT NOT NULL,\n  base_branch TEXT NOT NULL,\n  package_manager TEXT NOT NULL,\n  install_cmd TEXT NOT NULL,\n  test_cmd TEXT,\n  ci_workflow_name TEXT,\n  contribution_guide_path TEXT,\n  archived_at TEXT,\n  created_at TEXT NOT NULL\n);\n\nCREATE TABLE preambles (\n  preamble_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  body TEXT NOT NULL,\n  created_at TEXT NOT NULL\n);\n\nCREATE TABLE retry_templates (\n  template_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  kind TEXT NOT NULL,\n  body TEXT NOT NULL,\n  created_at TEXT NOT NULL\n);\n\nCREATE TABLE tasks (\n  task_id TEXT PRIMARY KEY,\n  repo_id TEXT NOT NULL REFERENCES repos(repo_id),\n  external_ref TEXT,\n  state TEXT NOT NULL,\n  branch_name TEXT NOT NULL,\n  tmux_id TEXT NOT NULL,\n  worktree_path TEXT NOT NULL,\n  pr_number INTEGER,\n  pr_url TEXT,\n  head_sha TEXT,\n  base_sha TEXT,\n  attempts_consumed INTEGER NOT NULL DEFAULT 0,\n  retry_budget INTEGER NOT NULL,\n  budget_exhausted INTEGER NOT NULL DEFAULT 0 CHECK (budget_exhausted IN (0, 1)),\n  tick_error TEXT,\n  slack_thread_ref TEXT,\n  claimed_at TEXT,\n  claim_id TEXT,\n  claim_expirations_consecutive INTEGER NOT NULL DEFAULT 0,\n  last_review_id_acted_on TEXT,\n  last_conflict_observation TEXT,\n  non_budget_respawns_consumed INTEGER NOT NULL DEFAULT 0,\n  next_escalation_seq INTEGER NOT NULL DEFAULT 1,\n  cancel_requested_at TEXT,\n  cancel_close_pr INTEGER NOT NULL DEFAULT 0 CHECK (cancel_close_pr IN (0, 1)),\n  cancel_keep_worktree INTEGER NOT NULL DEFAULT 0 CHECK (cancel_keep_worktree IN (0, 1)),\n  spawn_failures_consecutive INTEGER NOT NULL DEFAULT 0,\n  created_at TEXT NOT NULL,\n  updated_at TEXT NOT NULL\n);\n\nCREATE INDEX tasks_state_idx ON tasks(state);\n\nCREATE TABLE attempts (\n  attempt_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  task_id TEXT NOT NULL REFERENCES tasks(task_id),\n  attempt_number INTEGER NOT NULL,\n  preamble_id INTEGER NOT NULL REFERENCES preambles(preamble_id),\n  template_id INTEGER REFERENCES retry_templates(template_id),\n  reason TEXT NOT NULL,\n  consumed_budget INTEGER NOT NULL CHECK (consumed_budget IN (0, 1)),\n  tmux_session TEXT,\n  spawned_at TEXT,\n  remote_sha_at_spawn TEXT,\n  remote_sha_at_exit TEXT,\n  pr_existed_at_spawn INTEGER NOT NULL DEFAULT 0 CHECK (pr_existed_at_spawn IN (0, 1)),\n  ended_at TEXT,\n  exit_kind TEXT,\n  kill_intent TEXT,\n  UNIQUE (task_id, attempt_number)\n);\n\nCREATE UNIQUE INDEX one_pending_attempt_per_task\n  ON attempts(task_id)\n  WHERE spawned_at IS NULL;\n\nCREATE TABLE artifacts (\n  artifact_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  task_id TEXT NOT NULL REFERENCES tasks(task_id),\n  attempt_id INTEGER REFERENCES attempts(attempt_id),\n  kind TEXT NOT NULL,\n  file_path TEXT NOT NULL,\n  content_hash TEXT,\n  escalation_seq INTEGER,\n  escalation_nonce TEXT,\n  slack_pre_post_fence_ts TEXT,\n  slack_post_ts TEXT,\n  slack_recovered_post_ts TEXT,\n  captured_at TEXT NOT NULL\n);\n\nCREATE UNIQUE INDEX artifact_recovery_idempotency\n  ON artifacts(task_id, attempt_id, kind, content_hash)\n  WHERE content_hash IS NOT NULL AND attempt_id IS NOT NULL;\n\nCREATE INDEX artifacts_task_kind_attempt_idx\n  ON artifacts(task_id, kind, attempt_id);\n\nCREATE TABLE events (\n  event_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  task_id TEXT NOT NULL REFERENCES tasks(task_id),\n  attempt_id INTEGER REFERENCES attempts(attempt_id),\n  event_type TEXT NOT NULL,\n  from_state TEXT,\n  to_state TEXT,\n  payload_artifact_id INTEGER REFERENCES artifacts(artifact_id),\n  occurred_at TEXT NOT NULL\n);\n\nCREATE INDEX events_task_occurred_idx ON events(task_id, occurred_at);\n" },
  { name: "0002_deployment_adapters.sql", sql: "-- Slice 12 schema additions (per docs/quay-spec-deployment-adapters.md §5).\n-- Owns: task_tags table (clustering tags), tasks.authors_json column\n-- (TicketAuthor[] for Slack @-mention escalations).\n-- Foreign keys must be enabled at the connection level (PRAGMA foreign_keys = ON).\n--\n-- Deletion semantics for task_tags: no ON DELETE clause, so SQLite's default\n-- (RESTRICT / NO ACTION) applies — deleting a task that still has task_tags\n-- rows is rejected by the FK. Tasks are not normally deleted in Quay; if a\n-- caller ever needs to remove one, the rows in task_tags must be cleared\n-- first. Chosen for safety; spec §5 leaves the choice open.\n\nCREATE TABLE task_tags (\n  task_id TEXT NOT NULL REFERENCES tasks(task_id),\n  tag TEXT NOT NULL,\n  created_at TEXT NOT NULL,\n  PRIMARY KEY (task_id, tag)\n);\nCREATE INDEX task_tags_by_tag ON task_tags(tag);\n\nALTER TABLE tasks ADD COLUMN authors_json TEXT;\n" },
  { name: "0003_external_ref_unique.sql", sql: "-- Closes the read-before-write race in `quay enqueue --linear-issue`.\n--\n-- Two concurrent pollers can both pass the preflight lookupExistingTask()\n-- check (each reads zero rows) and then both attempt to INSERT a task for the\n-- same (repo_id, external_ref) pair. This partial unique index makes the\n-- second INSERT fail with SQLITE_CONSTRAINT_UNIQUE, which the caller catches\n-- to return the already-inserted row instead — converging on one task per\n-- ticket even under concurrent invocation (spec §3).\n--\n-- The WHERE clause excludes legacy tasks (external_ref IS NULL) so existing\n-- data continues to work without modification.\n\nCREATE UNIQUE INDEX tasks_repo_external_ref_unique\n  ON tasks(repo_id, external_ref)\n  WHERE external_ref IS NOT NULL;\n" },
  { name: "0004_tag_namespaces.sql", sql: "-- Layered tag vocabulary: per-deployment and per-repo namespaces with\n-- required/optional metadata.\n--\n-- Two tables instead of one because values and metadata have different\n-- cardinalities: a namespace can have many values but exactly one required\n-- flag. Keeping them separate avoids NULLable columns on the values table and\n-- makes the \"list all namespaces for a repo\" query a clean JOIN or two\n-- independent SELECTs.\n--\n-- The (scope, repo_id, namespace, ...) shape lets scope='repo' rows live in\n-- the same table as scope='deployment' rows. The CHECK constraint enforces\n-- the invariant that deployment-scoped rows never carry a repo_id and\n-- repo-scoped rows always do — the FK alone cannot express the NULL vs NOT\n-- NULL distinction.\n--\n-- Uniqueness is enforced by an expression index over IFNULL(repo_id, '')\n-- rather than a composite primary key. SQLite treats every NULL as distinct\n-- in unique constraints, so a composite PK that includes a nullable repo_id\n-- silently allows duplicate deployment rows. Folding NULL to '' in the index\n-- key collapses deployment rows into a single uniqueness scope.\n\nCREATE TABLE tag_namespaces (\n  scope TEXT NOT NULL,\n  repo_id TEXT,\n  namespace TEXT NOT NULL,\n  value TEXT NOT NULL,\n  created_at INTEGER NOT NULL,\n  FOREIGN KEY (repo_id) REFERENCES repos(repo_id),\n  CHECK ((scope='deployment' AND repo_id IS NULL)\n      OR (scope='repo' AND repo_id IS NOT NULL))\n);\nCREATE UNIQUE INDEX uq_tag_namespaces\n  ON tag_namespaces(scope, IFNULL(repo_id, ''), namespace, value);\nCREATE INDEX idx_tag_namespaces_scope_repo\n  ON tag_namespaces(scope, repo_id);\n\nCREATE TABLE tag_namespace_meta (\n  scope TEXT NOT NULL,\n  repo_id TEXT,\n  namespace TEXT NOT NULL,\n  required INTEGER NOT NULL,\n  created_at INTEGER NOT NULL,\n  FOREIGN KEY (repo_id) REFERENCES repos(repo_id),\n  CHECK ((scope='deployment' AND repo_id IS NULL)\n      OR (scope='repo' AND repo_id IS NOT NULL))\n);\nCREATE UNIQUE INDEX uq_tag_namespace_meta\n  ON tag_namespace_meta(scope, IFNULL(repo_id, ''), namespace);\n" },
  { name: "0005_attempts_agent_identity.sql", sql: "-- Per-attempt observability: snapshot which agent runtime executed this\n-- attempt. Format: \"<runtime>/<runtime_version>/<model_id>\" (single string,\n-- grep-friendly). NULL on rows that pre-date this migration; populated at\n-- spawn time for new rows by probing the agent binary.\n\nALTER TABLE attempts ADD COLUMN agent_identity TEXT;\n" },
  { name: "0006_attempts_exit_status.sql", sql: "-- Per-attempt observability: capture the OS-level termination of the\n-- worker pane alongside the existing `exit_kind` classification.\n--\n-- `exit_code` is the normal-exit status (0–255) when the process exited\n-- without a signal. `exit_signal` is the canonical SIG<name> when a signal\n-- terminated the process. Exactly one is non-NULL on a captured exit; both\n-- stay NULL on rows that pre-date this slice, on attempts whose substrate\n-- spawn never produced a real process (`exit_kind = 'spawn_failed'`), and\n-- on attempts where the wrapper shell was killed before it could record\n-- the inner agent's `$?` (tick's wall-clock kill, cancel finalizer kill).\n--\n-- Together with `exit_kind` (quay's classification), these answer \"what did\n-- the OS observe?\" — silent SIGKILL (OOM), SIGPIPE (closed stdout), normal\n-- exit 0, etc. — without re-deriving from session-log heuristics.\n\nALTER TABLE attempts ADD COLUMN exit_code INTEGER;\nALTER TABLE attempts ADD COLUMN exit_signal TEXT;\n" },
  { name: "0007_events_event_data.sql", sql: "-- Per-event observability: free-form JSON column carrying the *why*\n-- behind a transition that the (event_type, from_state, to_state)\n-- triple alone can't express. Keeps the events row compact while\n-- avoiding column proliferation across event types (\"which kind of\n-- no_progress?\", \"what was checked for spawn_window_no_evidence?\",\n-- \"what intent triggered kill_intent_set?\").\n--\n-- v1 is a TEXT column holding JSON by convention; the schema is\n-- per-event-type and not enforced. NULL on rows that pre-date this\n-- slice and on event-types this slice doesn't populate. Future\n-- tickets layer typed accessors on top.\n\nALTER TABLE events ADD COLUMN event_data TEXT;\n" },
  { name: "0008_attempts_diff_summary.sql", sql: "-- Per-attempt diff capture: lines-changed metadata between\n-- `remote_sha_at_spawn` and `remote_sha_at_exit`, computed once on the\n-- `pr_opened` transition. Reconstructable from `git log` between the two\n-- SHAs, but lifting it into a queryable column drops the join with the\n-- bare clone for retro analysis (\"avg lines per attempt across preamble\n-- versions\", \"attempts that touched config-only\").\n--\n-- v1 is a TEXT column holding JSON by convention (files_changed,\n-- insertions, deletions, files[]); not schema-enforced. NULL on rows\n-- pre-dating this slice, on attempts that never reached pr_opened, and\n-- on best-effort capture failures (missing SHA locally, git error) —\n-- those also surface as a `tick_error` event.\nALTER TABLE attempts ADD COLUMN diff_summary TEXT;\n" },
  { name: "0009_pr_review.sql", sql: "-- PR-review lifecycle support.\n--\n-- Adds the attempt/task metadata needed for review-only workers, separates\n-- reviewer preambles from code-worker preambles, and loosens the pending\n-- attempt invariant so an ended pending review attempt can be superseded by a\n-- newer SHA.\n\nALTER TABLE attempts ADD COLUMN head_sha TEXT;\nALTER TABLE attempts ADD COLUMN review_verdict TEXT;\nALTER TABLE attempts ADD COLUMN review_id TEXT;\n\nCREATE UNIQUE INDEX attempts_review_dedup_idx\n  ON attempts(task_id, head_sha)\n  WHERE reason = 'review_only'\n    AND head_sha IS NOT NULL\n    AND ended_at IS NULL;\n\nDROP INDEX IF EXISTS one_pending_attempt_per_task;\nCREATE UNIQUE INDEX one_pending_attempt_per_task\n  ON attempts(task_id)\n  WHERE spawned_at IS NULL AND ended_at IS NULL;\n\nALTER TABLE preambles ADD COLUMN kind TEXT NOT NULL DEFAULT 'code';\nCREATE INDEX preambles_kind_idx ON preambles(kind);\n\nALTER TABLE tasks ADD COLUMN review_infra_failures_consecutive INTEGER NOT NULL DEFAULT 0;\nALTER TABLE tasks ADD COLUMN review_infra_failure_head_sha TEXT;\n" },
  { name: "0010_repos_agent_override.sql", sql: "-- Per-repo agent overrides for worker and reviewer roles.\n--\n-- A NULL column means \"use the deployment default\" (the resolver falls\n-- back to `[agents].worker` / `[agents].reviewer`). A non-NULL column\n-- pins the role to a named entry under `[agents.invocations]`. The\n-- worker and reviewer columns are independent so operators can run e.g.\n-- a codex worker against a claude reviewer (\"second opinion\" mix).\n--\n-- Migration also adds `attempts.agent_name` so the spawn site records\n-- which registered agent ran the attempt — observability that doesn't\n-- depend on `agent_identity` (which is the binary + version string from\n-- the probe, not the registered key).\n\nALTER TABLE repos ADD COLUMN agent_worker TEXT;\nALTER TABLE repos ADD COLUMN agent_reviewer TEXT;\n\nALTER TABLE attempts ADD COLUMN agent_name TEXT;\n" },
  { name: "0011_orchestrator_handoffs.sql", sql: "-- Durable orchestrator handoff queue for tasks that enter\n-- awaiting-next-brief and need judgment outside `quay tick`.\n\nCREATE TABLE orchestrator_handoffs (\n  handoff_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  task_id TEXT NOT NULL REFERENCES tasks(task_id),\n  reason TEXT NOT NULL CHECK (\n    reason IN (\n      'worker_blocker',\n      'budget_exhausted',\n      'human_reply_ingested',\n      'manual_resume'\n    )\n  ),\n  state_event_id INTEGER NOT NULL REFERENCES events(event_id),\n  idempotency_key TEXT NOT NULL,\n  payload_json TEXT,\n  status TEXT NOT NULL DEFAULT 'pending' CHECK (\n    status IN ('pending', 'claimed', 'completed', 'cancelled')\n  ),\n  claim_id TEXT,\n  claimed_at TEXT,\n  completed_at TEXT,\n  created_at TEXT NOT NULL,\n  updated_at TEXT NOT NULL,\n  UNIQUE (idempotency_key),\n  UNIQUE (task_id, state_event_id, reason)\n);\n\nCREATE INDEX orchestrator_handoffs_status_created_idx\n  ON orchestrator_handoffs(status, created_at, handoff_id);\n\nCREATE INDEX orchestrator_handoffs_task_status_idx\n  ON orchestrator_handoffs(task_id, status, handoff_id);\n" },
  { name: "0012_agent_model_selection.sql", sql: "-- First-class agent/model selection snapshots.\n--\n-- Repo columns are role defaults. Task columns are immutable snapshots taken\n-- at enqueue / synthetic review scheduling time, so later config changes do\n-- not alter already-queued work. Attempt column records the intended model\n-- that was passed to the agent invocation.\n\nALTER TABLE repos ADD COLUMN model_worker TEXT;\nALTER TABLE repos ADD COLUMN model_reviewer TEXT;\n\nALTER TABLE tasks ADD COLUMN worker_agent TEXT;\nALTER TABLE tasks ADD COLUMN worker_model TEXT;\nALTER TABLE tasks ADD COLUMN reviewer_agent TEXT;\nALTER TABLE tasks ADD COLUMN reviewer_model TEXT;\n\nALTER TABLE attempts ADD COLUMN agent_model TEXT;\n" },
  { name: "0013_review_requests.sql", sql: "-- Durable review enrollment queue consumed by tick.\nCREATE TABLE review_requests (\n  request_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  task_id TEXT NOT NULL REFERENCES tasks(task_id),\n  repo_id TEXT NOT NULL REFERENCES repos(repo_id),\n  pr_number INTEGER NOT NULL,\n  head_sha TEXT NOT NULL,\n  source TEXT NOT NULL DEFAULT 'review-pr',\n  requested_by TEXT,\n  delivery_id TEXT,\n  tags_json TEXT,\n  reviewer_agent TEXT,\n  reviewer_model TEXT,\n  status TEXT NOT NULL CHECK (\n    status IN ('pending_ci', 'scheduled', 'superseded', 'discarded_terminal')\n  ),\n  scheduled_attempt_id INTEGER REFERENCES attempts(attempt_id),\n  superseded_by_request_id INTEGER REFERENCES review_requests(request_id),\n  created_at TEXT NOT NULL,\n  updated_at TEXT NOT NULL,\n  terminal_state TEXT\n);\n\nCREATE UNIQUE INDEX review_requests_unique_head\n  ON review_requests(task_id, head_sha);\n\nCREATE INDEX review_requests_pending_idx\n  ON review_requests(status, repo_id, pr_number, created_at);\n" },
  { name: "0014_task_objective_backfill.sql", sql: "-- Backfill task-level kind='task_objective' artifact rows for every task\n-- that existed before the shared code-worker prompt composer landed.\n--\n-- The composer's loadOriginalTaskObjective() requires a kind='task_objective'\n-- artifact with attempt_id IS NULL, written once at enqueue time. Without\n-- this backfill, any pre-existing active task would throw on its next CI /\n-- crash / stale / wall-clock / malformed retry, on review/conflict respawn,\n-- or on orchestrator submit-brief.\n--\n-- For legacy tasks, the raw original brief lives in the first attempt's\n-- (`attempt_number=1`, `reason='initial'`) brief artifact. The backfilled\n-- row points at the same on-disk file and copies the content_hash — no file\n-- writes are required. The `artifact_recovery_idempotency` unique index\n-- excludes `attempt_id IS NULL`, so the new task-level row never collides\n-- with the per-attempt brief it shadows.\n--\n-- The NOT EXISTS clause makes this migration safe to re-run.\n\nINSERT INTO artifacts (task_id, attempt_id, kind, file_path, content_hash, captured_at)\nSELECT\n  ar.task_id,\n  NULL,\n  'task_objective',\n  ar.file_path,\n  ar.content_hash,\n  strftime('%Y-%m-%dT%H:%M:%fZ', 'now')\nFROM artifacts ar\nJOIN attempts a ON a.attempt_id = ar.attempt_id\nWHERE ar.kind = 'brief'\n  AND a.attempt_number = 1\n  AND a.reason = 'initial'\n  AND NOT EXISTS (\n    SELECT 1\n      FROM artifacts ao\n     WHERE ao.task_id = ar.task_id\n       AND ao.kind = 'task_objective'\n       AND ao.attempt_id IS NULL\n  );\n" },
  { name: "0015_task_goals.sql", sql: "-- Task-level goal worker mode.\n-- quay: foreign_keys_off\n--\n-- A goal is owned by its Quay task, not scheduled independently. The task\n-- stays the scheduling unit; task_goals carries durable objective/status and\n-- accounting state across normal attempts.\n\nALTER TABLE tasks ADD COLUMN worker_execution TEXT NOT NULL DEFAULT 'oneshot'\n  CHECK (worker_execution IN ('oneshot', 'goal'));\n\nALTER TABLE attempts ADD COLUMN goal_id TEXT;\nALTER TABLE attempts ADD COLUMN goal_report_processed_at TEXT;\n\n-- Add the goal-mode no-progress handoff reason. SQLite cannot alter a CHECK\n-- constraint in place, so rebuild the table while preserving rows.\nALTER TABLE orchestrator_handoffs RENAME TO orchestrator_handoffs_old;\n\nCREATE TABLE orchestrator_handoffs (\n  handoff_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  task_id TEXT NOT NULL REFERENCES tasks(task_id),\n  reason TEXT NOT NULL CHECK (\n    reason IN (\n      'worker_blocker',\n      'budget_exhausted',\n      'human_reply_ingested',\n      'manual_resume',\n      'no_progress'\n    )\n  ),\n  state_event_id INTEGER NOT NULL REFERENCES events(event_id),\n  idempotency_key TEXT NOT NULL,\n  payload_json TEXT,\n  status TEXT NOT NULL DEFAULT 'pending' CHECK (\n    status IN ('pending', 'claimed', 'completed', 'cancelled')\n  ),\n  claim_id TEXT,\n  claimed_at TEXT,\n  completed_at TEXT,\n  created_at TEXT NOT NULL,\n  updated_at TEXT NOT NULL,\n  UNIQUE (idempotency_key),\n  UNIQUE (task_id, state_event_id, reason)\n);\n\nINSERT INTO orchestrator_handoffs (\n  handoff_id, task_id, reason, state_event_id, idempotency_key,\n  payload_json, status, claim_id, claimed_at, completed_at, created_at,\n  updated_at\n)\nSELECT\n  handoff_id, task_id, reason, state_event_id, idempotency_key,\n  payload_json, status, claim_id, claimed_at, completed_at, created_at,\n  updated_at\nFROM orchestrator_handoffs_old;\n\nDROP TABLE orchestrator_handoffs_old;\n\nCREATE INDEX orchestrator_handoffs_status_created_idx\n  ON orchestrator_handoffs(status, created_at, handoff_id);\n\nCREATE INDEX orchestrator_handoffs_task_status_idx\n  ON orchestrator_handoffs(task_id, status, handoff_id);\n\nCREATE TABLE task_goals (\n  task_id TEXT PRIMARY KEY NOT NULL REFERENCES tasks(task_id),\n  goal_id TEXT NOT NULL,\n  objective TEXT NOT NULL,\n  status TEXT NOT NULL CHECK (\n    status IN ('active', 'blocked', 'budget_limited', 'complete')\n  ),\n  token_budget INTEGER,\n  tokens_used INTEGER NOT NULL DEFAULT 0,\n  time_used_seconds INTEGER NOT NULL DEFAULT 0,\n  no_progress_active_count INTEGER NOT NULL DEFAULT 0,\n  last_attempt_id INTEGER REFERENCES attempts(attempt_id),\n  current_handoff_id INTEGER REFERENCES orchestrator_handoffs(handoff_id),\n  created_at TEXT NOT NULL,\n  updated_at TEXT NOT NULL,\n  completed_at TEXT,\n  CHECK (token_budget IS NULL OR token_budget > 0)\n);\n\nCREATE INDEX task_goals_status_idx ON task_goals(status);\n" },
  { name: "0016_task_base_branch.sql", sql: "-- Task-level effective base branch.\n--\n-- Existing tasks are backfilled from their repo default so later repo config\n-- changes do not alter already-enqueued work. New enqueue paths write the\n-- effective branch explicitly.\n\nALTER TABLE tasks ADD COLUMN base_branch TEXT;\n\nUPDATE tasks\n   SET base_branch = (\n     SELECT repos.base_branch\n       FROM repos\n      WHERE repos.repo_id = tasks.repo_id\n   )\n WHERE base_branch IS NULL;\n" },
  { name: "0017_goal_completion_audit.sql", sql: "-- Goal completion audit gate.\n-- quay: foreign_keys_off\n--\n-- `completion_pending` is an internal status: the worker has made a terminal\n-- completion claim, but Quay has not yet accepted the claim and entered the\n-- PR lifecycle.\n\nALTER TABLE task_goals RENAME TO task_goals_old;\n\nCREATE TABLE task_goals (\n  task_id TEXT PRIMARY KEY NOT NULL REFERENCES tasks(task_id),\n  goal_id TEXT NOT NULL,\n  objective TEXT NOT NULL,\n  status TEXT NOT NULL CHECK (\n    status IN (\n      'active',\n      'blocked',\n      'budget_limited',\n      'completion_pending',\n      'complete'\n    )\n  ),\n  token_budget INTEGER,\n  tokens_used INTEGER NOT NULL DEFAULT 0,\n  time_used_seconds INTEGER NOT NULL DEFAULT 0,\n  no_progress_active_count INTEGER NOT NULL DEFAULT 0,\n  last_attempt_id INTEGER REFERENCES attempts(attempt_id),\n  current_handoff_id INTEGER REFERENCES orchestrator_handoffs(handoff_id),\n  created_at TEXT NOT NULL,\n  updated_at TEXT NOT NULL,\n  completed_at TEXT,\n  CHECK (token_budget IS NULL OR token_budget > 0)\n);\n\nINSERT INTO task_goals (\n  task_id, goal_id, objective, status, token_budget,\n  tokens_used, time_used_seconds, no_progress_active_count,\n  last_attempt_id, current_handoff_id, created_at, updated_at, completed_at\n)\nSELECT\n  task_id, goal_id, objective, status, token_budget,\n  tokens_used, time_used_seconds, no_progress_active_count,\n  last_attempt_id, current_handoff_id, created_at, updated_at, completed_at\nFROM task_goals_old;\n\nDROP TABLE task_goals_old;\n\nCREATE INDEX task_goals_status_idx ON task_goals(status);\n" },
  { name: "0018_github_poll_backoff.sql", sql: "-- GitHub polling observability and quota protection.\n--\n-- `github_pr_polled_at` is a task-local timestamp used by tick to avoid\n-- taking full PR snapshots for low-priority states every scheduler minute.\n--\n-- `github_backoffs` stores global circuit-breaker windows. The current\n-- consumer is scope='graphql', set after GitHub reports API rate-limit\n-- exhaustion so subsequent background polling skips until reset.\n\nALTER TABLE tasks ADD COLUMN github_pr_polled_at TEXT;\n\nCREATE TABLE github_backoffs (\n  scope TEXT PRIMARY KEY,\n  pause_until TEXT NOT NULL,\n  reason TEXT NOT NULL,\n  observed_at TEXT NOT NULL,\n  repo_id TEXT\n);\n" },
  { name: "0019_pr_screenshot_request.sql", sql: "-- Soft task-level PR screenshot request.\n--\n-- When set, every code-worker prompt for the task asks the worker to include\n-- UI screenshots in the PR when the runtime can capture and attach/link them.\n-- This is intentionally advisory; Quay does not model worker capabilities yet.\n\nALTER TABLE tasks ADD COLUMN pr_screenshots_requested INTEGER NOT NULL DEFAULT 0\n  CHECK (pr_screenshots_requested IN (0, 1));\n" },
  { name: "0020_handoff_next_eligible_at.sql", sql: "-- Durable handoff queue backoff.\n--\n-- A human-wait timeout releases the task claim back to awaiting-next-brief,\n-- but the handoff should not immediately become drainable again ahead of\n-- newer pending handoffs. `next_eligible_at` is NULL for normal pending work\n-- and future-dated when a human wait needs a cooldown before re-notification.\n\nALTER TABLE orchestrator_handoffs ADD COLUMN next_eligible_at TEXT;\n\nCREATE INDEX orchestrator_handoffs_pending_eligible_idx\n  ON orchestrator_handoffs(status, next_eligible_at, created_at, handoff_id)\n  WHERE status = 'pending';\n" },
  { name: "0021_pr_screenshot_requirement.sql", sql: "-- Hard task-level PR screenshot requirement.\n--\n-- When set, enqueue has already verified that the resolved worker agent\n-- advertises screenshot capability. The flag persists the hard prompt mode\n-- across retries, goal continuations, and non-budget respawns.\n\nALTER TABLE tasks ADD COLUMN pr_screenshots_required INTEGER NOT NULL DEFAULT 0\n  CHECK (pr_screenshots_required IN (0, 1));\n" },
  { name: "0022_pr_adoption.sql", sql: "-- Human PR adoption support.\n--\n-- `authoring_mode` records who owns the branch-writing lifecycle. Synthetic\n-- review tasks are review-only until an operator explicitly adopts them; once\n-- adopted, Quay code workers may push the existing human PR branch, but branch\n-- cleanup must preserve that human-created remote branch by default.\n\nALTER TABLE tasks ADD COLUMN authoring_mode TEXT NOT NULL DEFAULT 'quay_owned'\n  CHECK (authoring_mode IN ('quay_owned', 'synthetic_review', 'adopted_external_pr'));\n\nUPDATE tasks\n   SET authoring_mode = 'synthetic_review'\n WHERE task_id LIKE 'pr-review-%';\n" },
  { name: "0023_orchestrator_outbox.sql", sql: "-- Shared durable outbox for orchestrator-owned side effects.\n--\n-- `orchestrator_handoffs` remains as a compatibility surface for existing\n-- human/advice workflows, but each handoff is now backed by an outbox item.\n-- New delivery-only side effects can use outbox_items directly without\n-- pretending to be task claims.\n\nCREATE TABLE outbox_items (\n  outbox_item_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  task_id TEXT NOT NULL REFERENCES tasks(task_id),\n  kind TEXT NOT NULL,\n  handler_class TEXT NOT NULL CHECK (\n    handler_class IN ('workflow_intervention', 'delivery')\n  ),\n  source_event_id INTEGER REFERENCES events(event_id),\n  idempotency_key TEXT NOT NULL,\n  payload_json TEXT,\n  route_hint_json TEXT,\n  status TEXT NOT NULL DEFAULT 'pending' CHECK (\n    status IN ('pending', 'claimed', 'completed', 'cancelled')\n  ),\n  claim_id TEXT,\n  claimed_at TEXT,\n  delivered_at TEXT,\n  completed_at TEXT,\n  last_error TEXT,\n  next_eligible_at TEXT,\n  created_at TEXT NOT NULL,\n  updated_at TEXT NOT NULL,\n  UNIQUE (idempotency_key)\n);\n\nCREATE UNIQUE INDEX outbox_items_task_source_kind_idx\n  ON outbox_items(task_id, source_event_id, kind)\n  WHERE source_event_id IS NOT NULL;\n\nCREATE INDEX outbox_items_status_created_idx\n  ON outbox_items(status, created_at, outbox_item_id);\n\nCREATE INDEX outbox_items_task_status_idx\n  ON outbox_items(task_id, status, outbox_item_id);\n\nCREATE INDEX outbox_items_pending_eligible_idx\n  ON outbox_items(status, next_eligible_at, created_at, outbox_item_id)\n  WHERE status = 'pending';\n\nALTER TABLE orchestrator_handoffs ADD COLUMN outbox_item_id INTEGER\n  REFERENCES outbox_items(outbox_item_id);\n\nINSERT INTO outbox_items (\n  task_id, kind, handler_class, source_event_id, idempotency_key,\n  payload_json, status, claim_id, claimed_at, completed_at,\n  next_eligible_at, created_at, updated_at\n)\nSELECT\n  task_id,\n  'workflow_intervention.' || reason,\n  'workflow_intervention',\n  state_event_id,\n  idempotency_key,\n  payload_json,\n  status,\n  claim_id,\n  claimed_at,\n  completed_at,\n  next_eligible_at,\n  created_at,\n  updated_at\nFROM orchestrator_handoffs;\n\nUPDATE orchestrator_handoffs\n   SET outbox_item_id = (\n     SELECT outbox_items.outbox_item_id\n       FROM outbox_items\n      WHERE outbox_items.idempotency_key = orchestrator_handoffs.idempotency_key\n   );\n\nCREATE INDEX orchestrator_handoffs_outbox_item_idx\n  ON orchestrator_handoffs(outbox_item_id);\n" },
  { name: "0024_task_retarget.sql", sql: "-- Link tasks created by `quay task retarget` back to their source task.\n-- The reverse link is recorded as event_data on the source task's\n-- `retargeted` audit event so existing task rows stay append-only except for\n-- their state transition.\n\nALTER TABLE tasks ADD COLUMN retargeted_from_task_id TEXT REFERENCES tasks(task_id);\n\nCREATE INDEX tasks_retargeted_from_idx\n  ON tasks(retargeted_from_task_id)\n  WHERE retargeted_from_task_id IS NOT NULL;\n" },
  { name: "0025_repo_preamble_overrides.sql", sql: "-- Per-repo preamble overrides for worker and reviewer roles.\n--\n-- NULL keeps the existing global behavior: resolve the latest preamble row for\n-- the attempt kind (code/review), creating the built-in default when needed.\n-- Non-NULL pins the repo role to a specific preambles.preamble_id so attempts\n-- record exact prompt provenance without affecting other repos.\n\nALTER TABLE repos ADD COLUMN preamble_worker INTEGER REFERENCES preambles(preamble_id);\nALTER TABLE repos ADD COLUMN preamble_reviewer INTEGER REFERENCES preambles(preamble_id);\n\nCREATE INDEX repos_preamble_worker_idx\n  ON repos(preamble_worker)\n  WHERE preamble_worker IS NOT NULL;\n\nCREATE INDEX repos_preamble_reviewer_idx\n  ON repos(preamble_reviewer)\n  WHERE preamble_reviewer IS NOT NULL;\n" },
  { name: "0026_ci_ignore_policy.sql", sql: "-- Configurable CI ignore policy, layered as deployment defaults plus repo\n-- registry overrides. The list columns store JSON arrays so existing repo\n-- lifecycle/export/import paths can treat policy as row-local metadata.\n\nALTER TABLE repos ADD COLUMN ci_ignore_mode TEXT NOT NULL DEFAULT 'inherit'\n  CHECK (ci_ignore_mode IN ('inherit', 'extend', 'replace'));\n\nALTER TABLE repos ADD COLUMN ci_ignored_check_names TEXT NOT NULL DEFAULT '[]';\nALTER TABLE repos ADD COLUMN ci_ignored_workflow_names TEXT NOT NULL DEFAULT '[]';\n" },
  { name: "0027_task_dependencies.sql", sql: "-- Generic task dependency persistence for dependency-aware Quay scheduling.\n-- This is intentionally source-agnostic; Linear ingestion is layered on later.\n\nCREATE TABLE task_dependencies (\n  dependency_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  dependent_task_id TEXT NOT NULL REFERENCES tasks(task_id),\n  dependency_task_id TEXT REFERENCES tasks(task_id),\n  dependency_source TEXT NOT NULL CHECK (\n    dependency_source IN ('linear', 'manual', 'quay')\n  ),\n  dependency_external_ref TEXT,\n  dependency_repo_id TEXT REFERENCES repos(repo_id),\n  kind TEXT NOT NULL CHECK (kind IN ('blocked_by')),\n  scope TEXT NOT NULL CHECK (scope IN ('normal', 'umbrella')),\n  required_state TEXT NOT NULL CHECK (\n    required_state IN ('merged', 'merged_to_feature_branch')\n  ),\n  satisfied_at TEXT,\n  created_at TEXT NOT NULL,\n  updated_at TEXT NOT NULL,\n  CHECK (dependency_task_id IS NOT NULL OR dependency_external_ref IS NOT NULL)\n);\n\nCREATE INDEX task_dependencies_dependent_idx\n  ON task_dependencies(dependent_task_id, satisfied_at, dependency_id);\n\nCREATE INDEX task_dependencies_dependency_task_idx\n  ON task_dependencies(dependency_task_id, required_state)\n  WHERE dependency_task_id IS NOT NULL;\n\nCREATE INDEX task_dependencies_external_ref_idx\n  ON task_dependencies(dependency_source, dependency_external_ref)\n  WHERE dependency_external_ref IS NOT NULL;\n" },
  { name: "0028_umbrella_workflows.sql", sql: "-- One-repo umbrella workflow persistence.\n--\n-- An umbrella workflow is a shared feature branch that ordinary task rows can\n-- target as their effective PR base. Final PR fields are nullable placeholders\n-- for the later reconciliation slice.\n\nCREATE TABLE umbrella_workflows (\n  umbrella_workflow_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  external_ref TEXT NOT NULL,\n  repo_id TEXT NOT NULL REFERENCES repos(repo_id),\n  base_branch TEXT NOT NULL,\n  feature_branch TEXT NOT NULL,\n  state TEXT NOT NULL DEFAULT 'active' CHECK (\n    state IN ('active', 'completed', 'cancelled')\n  ),\n  final_pr_task_id TEXT REFERENCES tasks(task_id),\n  final_pr_number INTEGER,\n  final_pr_url TEXT,\n  created_at TEXT NOT NULL,\n  updated_at TEXT NOT NULL,\n  UNIQUE (repo_id, external_ref)\n);\n\nCREATE UNIQUE INDEX umbrella_workflows_repo_feature_branch_unique\n  ON umbrella_workflows(repo_id, feature_branch);\n\nCREATE TABLE umbrella_tasks (\n  umbrella_task_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  umbrella_workflow_id INTEGER NOT NULL REFERENCES umbrella_workflows(umbrella_workflow_id),\n  task_id TEXT NOT NULL UNIQUE REFERENCES tasks(task_id),\n  external_ref TEXT NOT NULL,\n  created_at TEXT NOT NULL,\n  UNIQUE (umbrella_workflow_id, external_ref)\n);\n\nCREATE INDEX umbrella_tasks_workflow_idx\n  ON umbrella_tasks(umbrella_workflow_id, umbrella_task_id);\n" },
  { name: "0029_retained_cancelled_worktree_gc.sql", sql: "-- Tracks retained cancelled worktrees that have been garbage-collected by tick.\n\nALTER TABLE tasks ADD COLUMN worktree_cleaned_at TEXT;\n\nCREATE INDEX tasks_retained_cancelled_worktree_gc_idx\n  ON tasks(state, cancel_keep_worktree, worktree_cleaned_at, cancel_requested_at, updated_at);\n" },
  { name: "0030_umbrella_expected_tasks.sql", sql: "-- Persist the expected Linear child set for umbrella workflows.\n--\n-- This table records umbrella membership as observed at parent enqueue time.\n-- It lets Quay distinguish not-yet-enqueued children from children already\n-- completed outside Quay, without polling Linear from tick.\n\nCREATE TABLE umbrella_expected_tasks (\n  umbrella_expected_task_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  umbrella_workflow_id INTEGER NOT NULL REFERENCES umbrella_workflows(umbrella_workflow_id),\n  external_ref TEXT NOT NULL,\n  title TEXT,\n  linear_issue_id TEXT,\n  linear_issue_url TEXT,\n  state TEXT NOT NULL DEFAULT 'expected' CHECK (\n    state IN ('expected', 'linked', 'complete_without_quay')\n  ),\n  completion_source TEXT CHECK (\n    completion_source IS NULL OR completion_source IN ('linear', 'manual')\n  ),\n  completion_reason TEXT,\n  completed_at TEXT,\n  created_at TEXT NOT NULL,\n  updated_at TEXT NOT NULL,\n  UNIQUE (umbrella_workflow_id, external_ref)\n);\n\nCREATE INDEX umbrella_expected_tasks_workflow_state_idx\n  ON umbrella_expected_tasks(umbrella_workflow_id, state, external_ref);\n" },
  { name: "0031_task_dependency_hardening.sql", sql: "-- Tie umbrella dependency rows to their workflow and prevent duplicate edges.\n\nALTER TABLE task_dependencies\n  ADD COLUMN umbrella_workflow_id INTEGER REFERENCES umbrella_workflows(umbrella_workflow_id);\n\nCREATE UNIQUE INDEX task_dependencies_edge_unique\n  ON task_dependencies(\n    dependent_task_id,\n    dependency_source,\n    COALESCE(dependency_task_id, char(0)),\n    COALESCE(dependency_external_ref, char(0)),\n    COALESCE(dependency_repo_id, char(0)),\n    kind,\n    scope,\n    COALESCE(umbrella_workflow_id, -1)\n  );\n\nCREATE INDEX task_dependencies_umbrella_workflow_idx\n  ON task_dependencies(umbrella_workflow_id, dependent_task_id)\n  WHERE umbrella_workflow_id IS NOT NULL;\n" },
  { name: "0032_umbrella_workflow_linear_metadata.sql", sql: "-- Persist parent Linear issue metadata for final umbrella PR rendering.\n\nALTER TABLE umbrella_workflows\n  ADD COLUMN linear_issue_title TEXT;\n\nALTER TABLE umbrella_workflows\n  ADD COLUMN linear_issue_url TEXT;\n" },
  { name: "0033_pr_title.sql", sql: "-- Persist a lightweight PR title snapshot for Mission Control review cards.\n\nALTER TABLE tasks ADD COLUMN pr_title TEXT;\n" },
  { name: "0034_deployment_settings.sql", sql: "-- Mutable deployment settings. config.toml remains bootstrap/host wiring;\n-- this row owns operator-editable defaults after an explicit import/update.\n\nCREATE TABLE deployment_settings (\n  singleton_id INTEGER PRIMARY KEY CHECK (singleton_id = 1),\n  worker_agent TEXT,\n  worker_model TEXT,\n  reviewer_agent TEXT,\n  reviewer_model TEXT,\n  created_at TEXT NOT NULL,\n  updated_at TEXT NOT NULL\n);\n" },
  { name: "0035_review_findings.sql", sql: "-- Normalized storage for structured Quay reviewer findings.\n\nCREATE TABLE review_findings (\n  finding_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  task_id TEXT NOT NULL REFERENCES tasks(task_id),\n  attempt_id INTEGER NOT NULL REFERENCES attempts(attempt_id) ON DELETE CASCADE,\n  review_id TEXT NOT NULL,\n  head_sha TEXT NOT NULL,\n  ordinal INTEGER NOT NULL CHECK (ordinal >= 1),\n  severity TEXT NOT NULL CHECK (severity IN ('blocking', 'non_blocking')),\n  title TEXT NOT NULL,\n  body_markdown TEXT NOT NULL,\n  principle_text TEXT,\n  fingerprint TEXT NOT NULL,\n  created_at TEXT NOT NULL,\n  UNIQUE (attempt_id, fingerprint)\n);\n\nCREATE INDEX review_findings_review_idx\n  ON review_findings(review_id, head_sha);\n\nCREATE INDEX review_findings_task_idx\n  ON review_findings(task_id, head_sha, ordinal);\n\nCREATE TABLE review_finding_locations (\n  location_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  finding_id INTEGER NOT NULL REFERENCES review_findings(finding_id) ON DELETE CASCADE,\n  ordinal INTEGER NOT NULL CHECK (ordinal >= 1),\n  path TEXT,\n  start_line INTEGER CHECK (start_line IS NULL OR start_line >= 1),\n  end_line INTEGER CHECK (end_line IS NULL OR end_line >= 1),\n  url TEXT,\n  created_at TEXT NOT NULL\n);\n\nCREATE INDEX review_finding_locations_finding_idx\n  ON review_finding_locations(finding_id, ordinal);\n" },
  { name: "0035_work_items_runs.sql", sql: "-- Separate durable work-item identity from task execution runs.\n--\n-- `tasks` remains the run table: attempts/events/artifacts continue to point\n-- at task_id, while work_items carries the stable external identity.\n\nCREATE TABLE work_items (\n  work_item_id TEXT PRIMARY KEY,\n  source TEXT NOT NULL,\n  repo_id TEXT NOT NULL REFERENCES repos(repo_id),\n  external_ref TEXT NOT NULL,\n  created_at TEXT NOT NULL,\n  updated_at TEXT NOT NULL,\n  UNIQUE (source, repo_id, external_ref)\n);\n\nALTER TABLE tasks ADD COLUMN work_item_id TEXT REFERENCES work_items(work_item_id);\nALTER TABLE tasks ADD COLUMN run_number INTEGER;\nALTER TABLE tasks ADD COLUMN supersedes_task_id TEXT REFERENCES tasks(task_id);\n\nINSERT INTO work_items (\n  work_item_id, source, repo_id, external_ref, created_at, updated_at\n)\nSELECT\n  'wi:' || hex(randomblob(16)),\n  'linear',\n  repo_id,\n  external_ref,\n  MIN(created_at),\n  MAX(updated_at)\nFROM tasks\nWHERE external_ref IS NOT NULL\nGROUP BY repo_id, external_ref;\n\nINSERT INTO work_items (\n  work_item_id, source, repo_id, external_ref, created_at, updated_at\n)\nSELECT\n  'wi:' || task_id,\n  'synthetic',\n  repo_id,\n  task_id,\n  created_at,\n  updated_at\nFROM tasks\nWHERE external_ref IS NULL;\n\nUPDATE tasks\n   SET work_item_id = (\n         SELECT wi.work_item_id\n          FROM work_items wi\n          WHERE wi.source = 'linear'\n            AND wi.repo_id = tasks.repo_id\n            AND wi.external_ref = tasks.external_ref\n       )\n WHERE external_ref IS NOT NULL;\n\nUPDATE tasks\n   SET work_item_id = 'wi:' || task_id\n WHERE external_ref IS NULL;\n\nWITH numbered_runs AS (\n  SELECT\n    task_id,\n    ROW_NUMBER() OVER (\n      PARTITION BY work_item_id\n      ORDER BY\n        CASE WHEN retargeted_from_task_id IS NULL THEN 0 ELSE 1 END,\n        created_at,\n        task_id\n    ) AS backfilled_run_number\n  FROM tasks\n  WHERE work_item_id IS NOT NULL\n)\nUPDATE tasks\n   SET run_number = (\n         SELECT numbered_runs.backfilled_run_number\n           FROM numbered_runs\n          WHERE numbered_runs.task_id = tasks.task_id\n       )\n WHERE run_number IS NULL;\n\nDROP INDEX IF EXISTS tasks_repo_external_ref_unique;\n\nCREATE UNIQUE INDEX tasks_work_item_run_number_unique\n  ON tasks(work_item_id, run_number)\n  WHERE work_item_id IS NOT NULL AND run_number IS NOT NULL;\n\n-- Mirrors TASK_TERMINAL_STATES in src/core/task_state.ts.\nCREATE UNIQUE INDEX one_active_run_per_work_item\n  ON tasks(work_item_id)\n  WHERE work_item_id IS NOT NULL\n    AND cancel_requested_at IS NULL\n    AND state NOT IN (\n      'cancelled',\n      'merged_to_feature_branch',\n      'merged',\n      'closed_unmerged'\n    );\n\nCREATE INDEX tasks_work_item_idx\n  ON tasks(work_item_id, task_id)\n  WHERE work_item_id IS NOT NULL;\n\nCREATE INDEX tasks_supersedes_task_idx\n  ON tasks(supersedes_task_id)\n  WHERE supersedes_task_id IS NOT NULL;\n" },
  { name: "0036_review_finding_external_links.sql", sql: "-- Provider links created from persisted review findings.\n\nCREATE TABLE review_finding_external_links (\n  link_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  finding_id INTEGER REFERENCES review_findings(finding_id) ON DELETE SET NULL,\n  task_id TEXT NOT NULL REFERENCES tasks(task_id),\n  review_id TEXT NOT NULL,\n  fingerprint TEXT NOT NULL,\n  provider TEXT NOT NULL,\n  provider_external_id TEXT NOT NULL,\n  provider_url TEXT NOT NULL,\n  outbox_item_id INTEGER REFERENCES outbox_items(outbox_item_id),\n  created_at TEXT NOT NULL,\n  updated_at TEXT NOT NULL,\n  UNIQUE (provider, task_id, review_id, fingerprint)\n);\n\nCREATE INDEX review_finding_external_links_finding_idx\n  ON review_finding_external_links(finding_id);\n" },
  { name: "0037_work_items_repo_id_repair.sql", sql: "-- quay: foreign_keys_off\n-- Repair deployments that applied an older 0035_work_items_runs.sql before\n-- work_items.repo_id was added. Migrations are tracked by filename, so those\n-- DBs need a forward-only rebuild even though the checked-in 0035 is now fixed.\n\nCREATE TABLE work_items_repaired (\n  work_item_id TEXT PRIMARY KEY,\n  source TEXT NOT NULL,\n  repo_id TEXT NOT NULL REFERENCES repos(repo_id),\n  external_ref TEXT NOT NULL,\n  created_at TEXT NOT NULL,\n  updated_at TEXT NOT NULL,\n  UNIQUE (source, repo_id, external_ref)\n);\n\nINSERT INTO work_items_repaired (\n  work_item_id, source, repo_id, external_ref, created_at, updated_at\n)\nWITH grouped AS (\n  SELECT\n    wi.work_item_id AS old_work_item_id,\n    wi.source,\n    wi.external_ref,\n    t.repo_id,\n    MIN(wi.created_at) AS created_at,\n    MAX(wi.updated_at) AS updated_at\n  FROM work_items wi\n  JOIN tasks t ON t.work_item_id = wi.work_item_id\n  GROUP BY wi.work_item_id, wi.source, wi.external_ref, t.repo_id\n), repo_counts AS (\n  SELECT old_work_item_id, COUNT(*) AS repo_count\n  FROM grouped\n  GROUP BY old_work_item_id\n)\nSELECT\n  CASE\n    WHEN repo_counts.repo_count = 1 THEN grouped.old_work_item_id\n    ELSE grouped.old_work_item_id || ':' || grouped.repo_id\n  END AS work_item_id,\n  grouped.source,\n  grouped.repo_id,\n  grouped.external_ref,\n  grouped.created_at,\n  grouped.updated_at\nFROM grouped\nJOIN repo_counts ON repo_counts.old_work_item_id = grouped.old_work_item_id;\n\nUPDATE tasks\n   SET work_item_id = (\n         SELECT repaired.work_item_id\n           FROM work_items old\n           JOIN work_items_repaired repaired\n             ON repaired.source = old.source\n            AND repaired.external_ref = old.external_ref\n            AND repaired.repo_id = tasks.repo_id\n          WHERE old.work_item_id = tasks.work_item_id\n          LIMIT 1\n       )\n WHERE work_item_id IS NOT NULL;\n\nDROP TABLE work_items;\nALTER TABLE work_items_repaired RENAME TO work_items;\n" },
  { name: "0038_review_protocol_provenance.sql", sql: "-- Durable reviewer protocol provenance.\n--\n-- Review guidance remains stored in attempts.preamble_id for compatibility\n-- with existing prompt/guidance history. The static review result protocol is\n-- code-owned, so review attempts also snapshot the protocol version that was\n-- prepended to their final_prompt. NULL means the attempt predates this\n-- migration or is not a review attempt.\n\nALTER TABLE attempts ADD COLUMN review_protocol_version TEXT;\n\nCREATE INDEX attempts_review_protocol_version_idx\n  ON attempts(review_protocol_version)\n  WHERE review_protocol_version IS NOT NULL;\n" },
  { name: "0039_repo_guidance.sql", sql: "-- Additive per-repo prompt guidance.\n--\n-- `preambles` remains the full global/pinned preamble stream. This table is\n-- a separate append-only stream for small repo-specific appendices that compose\n-- on top of the selected preamble instead of replacing it.\n\nCREATE TABLE repo_guidance (\n  guidance_id INTEGER PRIMARY KEY AUTOINCREMENT,\n  repo_id TEXT NOT NULL REFERENCES repos(repo_id),\n  role TEXT NOT NULL CHECK (role IN ('worker', 'reviewer')),\n  body TEXT NOT NULL,\n  created_at TEXT NOT NULL\n);\n\nCREATE INDEX repo_guidance_repo_role_idx\n  ON repo_guidance(repo_id, role, guidance_id DESC);\n\nALTER TABLE attempts ADD COLUMN repo_guidance_id INTEGER REFERENCES repo_guidance(guidance_id);\n\nCREATE INDEX attempts_repo_guidance_id_idx\n  ON attempts(repo_guidance_id)\n  WHERE repo_guidance_id IS NOT NULL;\n" },
];

export const EMBEDDED_TICKET_SCHEMA = "# Quay default ticket_schema.toml\n# Override at ${QUAY_CONFIG_DIR:-$HOME/.quay}/ticket_schema.toml.\n# Field set is aligned 1:1 with the quay-config block (per\n# docs/quay-spec-deployment-adapters.md §10) plus body length sanity.\n\n[required.body]\ntype = \"string\"\nmin_length = 10\nmax_length = 50000\n\n[required.tags]\ntype = \"list\"\nitem_type = \"string\"\nmin_count = 1\ncharset = \"lowercase_alphanum_dash\"\nunique = true\n\n[optional.slack_thread]\ntype = \"string\"\npattern = '^[A-Z0-9]+:\\d+\\.\\d+$'\ndescription = \"Slack thread reference: <channel_id>:<message_ts>. Optional: tickets without an originating Slack discussion can omit it. Escalation degrades cleanly to a no-op when absent (per substrate spec, src/core/tick.ts:1019).\"\n\n[required.repo]\ntype = \"string\"\nmin_length = 1\npattern = '^[A-Za-z0-9._-]+$'\ndescription = \"Target repo ID. Must match a repo registered with `quay repo add`. Mirrors the quay-config block's `repo:` field 1:1, and the charset matches `repoIdSchema` in src/core/repos/schema.ts so existing deployments with uppercase, `.`, or `_` repo IDs are not silently locked out.\"\n\n[required.authors]\ntype = \"list\"\nitem_type = \"object\"\nmin_count = 1\ndescription = \"Humans associated with the ticket, ordered by involvement (most-involved first). Mirrors the quay-config block's `authors:` list 1:1.\"\n\n[required.authors.fields.name]\ntype = \"string\"\nmin_length = 1\n\n[required.authors.fields.slack_id]\ntype = \"string\"\npattern = '^U[A-Z0-9]+$'\ndescription = \"Bare Slack user ID, e.g. U06TDC56VJB. Same format as the block.\"\n\n[optional.external_ref]\ntype = \"string\"\ndescription = \"Source-system identifier (e.g., 'ITRY-1276'). Stored opaquely by Quay as tasks.external_ref.\"\n\n[optional.worker_execution]\ntype = \"enum\"\nallowed = [\"oneshot\", \"goal\"]\ndescription = \"Worker execution mode. Defaults to oneshot; goal enables durable Quay goal worker mode.\"\n\n[optional.base_branch]\ntype = \"string\"\nmin_length = 1\nmax_length = 255\npattern = '^(?!refs/)(?!origin/)(?!@$)(?!.*@\\{)(?!.*\\.\\.)(?!.*//)(?!/)(?!.*[/.]$)(?!.*(?:^|/)\\.)(?!.*(?:^|/)[^/]*\\.lock(?:/|$))[A-Za-z0-9._/-]+$'\ndescription = \"Task-level PR base override. When present, Quay branches from origin/<base_branch> and instructs the worker to open the PR into that same branch without changing the repo default.\"\n";

export interface EmbeddedUiAsset {
  readonly path: string;
  readonly contentBase64: string;
}

export const EMBEDDED_UI_ASSETS: readonly EmbeddedUiAsset[] = [

];
